// DaxlinePro fonts voor jsPDF – automatisch gegenereerd
// Laad dit bestand NA jsPDF maar VOOR generateUrenstaat()
(function() {
    var fonts = {};
    fonts["DaxlinePro-Regular"] = "";
    fonts["DaxlinePro-Bold"] = "";

    // Wacht tot jsPDF geladen is, registreer dan de fonts
    function tryRegister() {
        if (!window.jspdf) { setTimeout(tryRegister, 200); return; }
        var jsPDF = window.jspdf.jsPDF;
        // Hook into jsPDF font system
        var callAddFont = function() {
            // Regular
            this.addFileToVFS('DaxlinePro-Regular.otf', fonts['DaxlinePro-Regular']);
            this.addFont('DaxlinePro-Regular.otf', 'DaxlinePro', 'normal');
            // Bold
            this.addFileToVFS('DaxlinePro-Bold.otf', fonts['DaxlinePro-Bold']);
            this.addFont('DaxlinePro-Bold.otf', 'DaxlinePro', 'bold');
        };
        jsPDF.API.events.push(['addFonts', callAddFont]);
        console.log('DaxlinePro fonts geregistreerd bij jsPDF');
    }
    tryRegister();
})();
